#!/usr/bin/env bash
#
# tests/protocol/kerberos/test_tgsreq.sh — Tests Kerberos TGS-REQ / TGS-REP
#

ensh::import protocol/kerberos/tgsreq

readonly _TEST_TGT_ASREP_HEX=""
readonly _TEST_TGSREP_HEX=""

test::kerberos_tgsreq_build_rc4_request() {
    local req
    ENSH_KRB5_TGSREQ_CTIME="20370913024805Z" \
    ENSH_KRB5_TGSREQ_CUSEC="654321" \
    ENSH_KRB5_TGSREQ_CONFOUNDER_HEX="1122334455667788" \
    ENSH_KRB5_TGSREQ_NONCE_HEX="12345678" \
    ENSH_KRB5_TGSREQ_TILL="20370913024805Z" \
        kerberos::tgsreq::build req \
            "${_TEST_TGT_ASREP_HEX}" \
            "00112233445566778899AABBCCDDEEFF" \
            "HTTP/web01.pirate.htb"

    local expected="6C8201613082015DA103020105A20302010CA381E83081E53081E2A103020101"
    expected+="A281DA0481D76E81D43081D1A003020105A10302010EA20703050000000000"
    expected+="A3526150304EA003020105A10C1B0A5049524154452E485442"
    expected+="A21F301DA003020102A11630141B066B72627467741B0A5049524154452E485442"
    expected+="A3183016A003020117A103020102A20A040801020304AABBCCDD"
    expected+="A4683066A003020117A25F045D6722F3741015E0ADA99B41C9E6AD8A2BAAFC82D9D03924C5140AB34D1C7CE712471431EEB456F3D1B2262182F7791B98F0759201A9C5FC5201D9B4D7851B198583F23100D4C142AEAA3B97B646AA75DAA50757F98427670FBB0BB14E41"
    expected+="A4663064A00703050040810010"
    expected+="A20C1B0A5049524154452E485442"
    expected+="A3233021A003020101A11A30181B04485454501B1077656230312E7069726174652E687462"
    expected+="A511180F32303337303931333032343830355A"
    expected+="A706020412345678"
    expected+="A80B3009020117020112020111"

    assert::equal "${req}" "${expected}" "TGS-REQ RC4 doit matcher le DER de référence"
}

test::kerberos_tgsreq_build_rejects_unsupported_tgt_etype() {
    local req=""
    if kerberos::tgsreq::build req "${_TEST_TGSREP_HEX}" "00112233445566778899AABBCCDDEEFF" "HTTP/web01.pirate.htb"; then
        assert::equal "ok" "fail" "build doit refuser un TGT non RC4"
    else
        assert::equal "fail" "fail" "build refuse bien un TGT non RC4"
    fi
}

test::kerberos_tgsreq_parse_tgsrep() {
    declare -A parsed=()
    kerberos::tgsreq::parse_tgsrep "${_TEST_TGSREP_HEX}" parsed

    assert::equal "${parsed[realm]}" "PIRATE.HTB" "realm du ticket"
    assert::equal "${parsed[sname]}" "HTTP/web01.pirate.htb" "principal de service"
    assert::equal "${parsed[ticket_etype]}" "23" "etype du ticket de service"
    assert::equal "${parsed[ticket_kvno]}" "5" "kvno du ticket de service"
    assert::equal "${parsed[ticket_cipher]}" "A1A2A3A4A5A6A7A8B1B2B3B4B5B6B7B8C1C2C3C4C5C6C7C8" "cipher du ticket de service"
}
